query:
SELECT 
  COUNT(*) as total,
  MIN(comissao) as min_com, MAX(comissao) as max_com, AVG(comissao) as avg_com,
  MIN(valorFinanciado) as min_vf, MAX(valorFinanciado) as max_vf, AVG(valorFinanciado) as avg_vf
FROM pro_rata;
SELECT nrOperacao, comissao, valorFinanciado, vlr, qtdFaltaReceber FROM pro_rata WHERE nrOperacao IN ('897822200','186418790','151198856') LIMIT 5;

